var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"실험 기지로 돌아갈 줄 알았는데- 정말 그림자를 토벌하러 갈 셈인가요?","JPN":"実験基地に帰るのかと思いましたが……本当にシャドウ討伐に向かうつもりですか？","ENG":"I thought you would go back to the testing base. Are you going to eliminate the Shadow?","TWN":"我以為你會回到實驗基地。真的要去討伐暗影嗎？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"잡아야지. 그림자는 한 번 놓치면 기약이 없으니까.","JPN":"そうだ。シャドウを1度逃がしたら、次のチャンスはいつになるかわからない。","ENG":"I must do now, as there is no guarantee of another chance to defeat a Shadow.","TWN":"是必須。暗影一旦錯過就不知道什麼時候會再出現。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"발키리를 없애는 게 당신의 가장 큰 소망인 줄 알았는데요.","JPN":"ヴァルキリーを始末することこそ、あなたの一番の望みだと思っていました。","ENG":"I thought getting rid of the Valkyrie was your biggest wish.","TWN":"我以為消滅女武神是你最大的願望。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"죽이지 못해도 힘을 절반으로 만드는 덴 성공했어.","JPN":"殺すことはできなかったが、力を半分にすることはできた。","ENG":"Although she's not dead, I did succeed in halving her strength.","TWN":"雖然沒能殺死她，但也成功削弱了她一半的力量。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"너도 그걸 원했잖아? 삼하인.","JPN":"君もそれを望んでいたのでは？　サウィン。","ENG":"And didn't you want that too, Samhain?","TWN":"這不也是你想要的嗎？薩溫。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"확실히… 계약대로 발키리의 힘을 약화시켰으니- 더 이상 제가 참견할 일은 아니군요.","JPN":"そうですね……契約どおりヴァルキリーの力を弱らせた。これ以上私が口を出す必要はありません。","ENG":"Yes... You did weaken her powers as you promised... So, it is not my place to meddle anymore.","TWN":"是的……你按照契約削弱了女武神的力量……接下來就不是我該插手的事了。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만, 당신이 감정을 앞세워 판단을 바꾸는 건 드문 일이에요.","JPN":"ですが、あなたが感情を優先して判断を変えるとは珍しい。","ENG":"However, it is rare of you to change your decision based on your emotions.","TWN":"但你很少會讓感情左右你的判斷。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"맞아. 네 경고처럼 내 인간성이 계획을 그르친 걸지도 모르지.","JPN":"そうだ。君が警告したとおり、私の中の人間性に計画を邪魔されたのかもしれない。","ENG":"You're right. Perhaps my humanity may have blundered the plan like you warned.","TWN":"嗯。就像你警告的那樣，我的人性可能破壞了計畫。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"패러독스를 우물에 혼자 빠뜨리면, 발키리의 운명이 그자를 살리기 위해 권능을 쓸 줄 알았는데…","JPN":"パラドックスを1人で井戸に入らせれば、ヴァルキリーの運命が彼女を助けるために権能を使うだろうと思ったが……","ENG":"I thought Valkyrie's fate would use her power to save Paradox if she fell into the Well by herself...","TWN":"如果把悖論單獨扔進井裡，我推斷女武神會用她的權能去救她……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그 영향이 뜻밖의 인물을 데려올 줄은 몰랐어.","JPN":"その影響を受けて、思いがけない人物を連れてくる結果は想定していなかった。","ENG":"But I didn't expect it would result in bringing back an unexpected person.","TWN":"但那個決定竟然會帶來意想不到的人物。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"흐음- 당신의 마음을 건드린 게 그 아이였군요?","JPN":"ふむ……ではあの子があなたの心を動かしたのですね。","ENG":"Hmm... Was it that child who touched your heart?","TWN":"嗯……是那個孩子觸動了你的心嗎？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>파블린</color>이란 이름은… 당신이 의무관 시절 살리지 못한 임산부이잖습니까?","JPN":"<color=#ffd34c>パブリン</color>という名前は……あなたが医務官だった頃、助けられなかった妊婦でしょう？","ENG":"<color=#ffd34c>Pavlin</color>... Wasn't that the name of the pregnant women you could not save when you were a medical officer?","TWN":"那個叫<color=#ffd34c>帕芙琳</color>的女人……不就是你還是醫務官時沒能救活的那個孕婦嗎？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그러게. 운명이란 건 참 얄궂네.","JPN":"そうだな。運命とは皮肉なものだ。","ENG":"Yeah. Fate can be cruel at times.","TWN":"是啊，命運真是太討厭了。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이번 세계에서조차, 그녀를 구하지 못했는데…","JPN":"今回の世界ですら、彼女を救えなかったのに……","ENG":"Even in this world, I wasn't able to save her...","TWN":"即使在這個世界，我也沒能拯救她……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"오늘 그곳에서 그녀의 아이를 만나게 될 줄이야.","JPN":"今日あの場所で彼女の子どもに出会うとは。","ENG":"Who would've known I'd meet her daughter here today.","TWN":"誰又會料到會在那遇到她的孩子呢？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그 아이가 당신에게 그렇게 각별하다면, 어째서 데려오지 않았죠?","JPN":"あなたにとってあの子がそれほどに特別な存在なら、なぜ連れて来なかったのですか？","ENG":"If that child means so much to you, then why didn't to take her with you?","TWN":"如果那個孩子對你如此重要，為什麼不把她留在身邊……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"난 내 곁에 소중한 걸 두지 않아.","JPN":"私は大切なものを側に置いたりしない。","ENG":"I don't keep things I cherish next to me.","TWN":"我不會把珍貴的東西留在身邊。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"필요한 것만 두고, 이용할 뿐이지.","JPN":"必要なものだけを側に置き、利用するだけだ。","ENG":"Only necessities that I use.","TWN":"只留下需要的、能利用的而已。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"소중한 것이라…","JPN":"大切なもの、ね……","ENG":"Things you cherish...","TWN":"珍貴的東西啊……"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"곧 그들 앞에 나타날 <color=#ffd34c>불청객</color>과 엮이게 되면, 그 소중한 아이도 살아남기 힘들 텐데요.","JPN":"まもなく彼らの前に現れる<color=#ffd34c>招かれざる客</color>と接点ができてしまったら、あの子も生き残れないはずです。","ENG":"Soon, when they encounter the <color=#ffd34c>uninvited</color>, and the child's chances of survival will be unlikely.","TWN":"如果與即將出現在他們面前的<color=#ffd34c>不速之客</color>糾纏在一起，那個孩子也很難生存下來喔？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"괜찮아. 관리자가 곁에 있으니까.","JPN":"大丈夫だ。管理者がいる。","ENG":"It's fine. She's with the Administrator.","TWN":"沒事的，有管理者在她身邊。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"권총 한 발에 죽을 만큼 연약한 인간이지만, 그 운명은 마왕보다 질기거든.","JPN":"銃弾1発で死ぬほど非力な人間ではあるが、その運命は魔王よりもしぶとい。","ENG":"He might be a weak human who can be killed by a single bullet, but his fate is tougher than a Demon Lord's.","TWN":"雖然是脆弱到一顆子彈就能殺死的人類，但他的命運比魔王還要頑強。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그자는 타인의 희생을 종용할만큼 냉혈한이기도 하죠.","JPN":"ですが、彼は他人に犠牲を強いるほど冷血な人間でもある。","ENG":"He is also cold-blooded enough to convince others to make sacrifices.","TWN":"但那個人也是個可以冷血到強迫他人犧牲的人。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"과연 관리자가 그 아이의 운명까지 지키려 할까요?","JPN":"果たして管理者があの子の運命までをも、守ろうとするでしょうか？","ENG":"Do you really think the Administrator will try to protect the child's fate?","TWN":"管理者真的會守護那個孩子的命運嗎？"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"글쎄. 그런 건 이제 내 몫이 아니야.","JPN":"さあな。それはもう私の手の届く範疇じゃない。","ENG":"Well, that's not my problem anymore.","TWN":"哼，這已經不是我的事了。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"관리자의 선택에 맡겨야겠지.","JPN":"管理者の選択に任せるしかないだろうな。","ENG":"It's up to what the Administrator chooses.","TWN":"應該交給管理者來選擇。"},"stage":{"bg":"HELI_NIGHT_3","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SCIENTIST_SWANSONG_NPC_NULL","text":{"KOREA":"자, 서둘러! 관리국의 범죄자들을 연행해!","JPN":"さあ、急げ！　管理局の犯罪者たちを連行するんだ！","ENG":"Hurry up! Arrest those Administration criminals!","TWN":"快，抓緊時間！把管理局的犯罪分子都抓起來！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SCIENTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};